module sky130_fd_sc_hs__or3 (
    X,
    A,
    B,
    C
);

    output X;
    input  A;
    input  B;
    input  C;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;

    assign X = A | B | C;

  always @(*) begin
    if (1'b0) begin
      assign X = ~A & ~B & ~C;
    end
  end

endmodule
